ops.replace_with:
.card { background: var(--surface); border: 1px solid var(--surface-light); border-left: 2px solid var(--primary); padding: 15px; margin-bottom: 15px; position: relative; }

/* Dashboard UI Additions */
.cat-group { margin-bottom: 15px; border: 1px solid #222; background: rgba(0,0,0,0.3); }
.cat-header { 
    background: var(--surface-light); padding: 12px 15px; cursor: pointer; 
    display: flex; justify-content: space-between; align-items: center; 
    border-left: 4px solid var(--primary); font-weight: bold; font-size: 0.9rem; 
    text-transform: uppercase; letter-spacing: 1px;
}
.cat-header.crisis { border-left-color: var(--danger); color: var(--danger); }
.cat-header.surv { border-left-color: var(--success); color: var(--success); }
.cat-header.sys { border-left-color: var(--primary); color: var(--primary); }

.cat-content { display: none; padding: 10px; }
.cat-content.open { display: block; }

.cmd-tile { 
    background: #15171a; border: 1px solid #222; margin-bottom: 8px; 
    transition: 0.2s; overflow: hidden;
}
.cmd-tile-main {
    padding: 12px; display: flex; align-items: center; justify-content: space-between; cursor: pointer;
}
.cmd-tile-main:active { background: #1a1c20; }
.cmd-name { font-size: 0.85rem; color: #eee; }
.cmd-icon { opacity: 0.5; font-size: 1rem; }

.cmd-drawer { 
    display: none; padding: 15px; background: #0a0b0d; border-top: 1px solid #222; 
    animation: slideDown 0.2s ease-out;
}
.cmd-drawer.open { display: block; }

.cmd-actions { display: flex; gap: 8px; margin-top: 10px; }

@keyframes slideDown { from { opacity: 0; transform: translateY(-5px); } to { opacity: 1; transform: translateY(0); } }

