function renderCommandDashboard() {
    const container = document.getElementById('cmd-dashboard-container');
    container.innerHTML = COMMAND_GROUPS.map(group => `
        <div class="cat-group" id="cat-${group.id}">
            <div class="cat-header ${group.css}" onclick="toggleDashboardCat('${group.id}')" data-search="${group.search}">
                <span>${group.label}</span>
                <span class="cat-toggle-icon">▼</span>
            </div>
            <div class="cat-content" id="content-${group.id}">
                ${group.commands.map(cmd => `
                    <div class="cmd-tile" id="tile-${cmd.id}">
                        <div class="cmd-tile-main" onclick="toggleCmdDrawer('${cmd.id}')">
                            <div class="cmd-name"><span style="margin-right:10px">${cmd.icon}</span> ${cmd.name}</div>
                            <div style="display:flex; gap:8px;">
                                <button class="btn-tag" onclick="tagCmd('${cmd.id}', this); event.stopPropagation();">🏷️</button>
                                <button class="btn-status" onclick="auditCmd('${cmd.id}'); event.stopPropagation();">?</button>
                            </div>
                        </div>
                        <div class="cmd-drawer" id="drawer-${cmd.id}">
                            <div class="drawer-inputs">
                                ${cmd.inputs.map(input => `
                                    <div style="margin-bottom:10px;">
                                        <label style="display:block; font-size:0.6rem; color:var(--primary); margin-bottom:4px;">${input.label}</label>
                                        ${input.type === 'select' ? `
                                            <select id="${input.id}" style="width:100%; background:#000; color:var(--primary); border:1px solid #333; padding:8px;">
                                                ${input.options.map(o => `<option value="${o.v}">${o.l}</option>`).join('')}
                                            </select>
                                        ` : input.type === 'textarea' ? `
                                            <textarea id="${input.id}" placeholder="${input.placeholder || ''}" style="width:100%; height:80px;"></textarea>
                                        ` : `
                                            <input type="${input.type}" id="${input.id}" value="${input.val !== undefined ? input.val : ''}" placeholder="${input.placeholder || ''}" style="width:100%">
                                        `}
                                    </div>
                                `).join('')}
                            </div>
                            <div class="cmd-actions">
                                <button class="btn" style="flex:1; background:var(--primary); color:#000;" onclick="sendCmd('${cmd.id}')">BROADCAST</button>
                                <button class="btn danger" style="padding:8px 15px;" onclick="toggleCmdDrawer('${cmd.id}')">CANCEL</button>
                            </div>
                        </div>
                    </div>
                `).join('')}
            </div>
        </div>
    `).join('');
}

function toggleDashboardCat(id) {
    const content = document.getElementById('content-' + id);
    const icon = document.querySelector(`#cat-${id} .cat-toggle-icon`);
    const isOpen = content.classList.contains('open');

    // Close others if you want accordion behavior, or just toggle
    content.classList.toggle('open');
    icon.innerText = isOpen ? '▼' : '▲';
}

function toggleCmdDrawer(id) {
    const drawer = document.getElementById('drawer-' + id);
    const isOpen = drawer.classList.contains('open');

    // Close all other drawers in the same section for cleanliness
    drawer.closest('.cat-content').querySelectorAll('.cmd-drawer').forEach(d => d.classList.remove('open'));

    if (!isOpen) drawer.classList.add('open');
}

